// TestDeviceTouchEventOnlyUpdatesSequenceData
// tests the scenario when device touch events only updates the sequence data
// and does not update the device document itself.
func TestDeviceTouchEventOnlyUpdatesSequenceData(t *testing.T) {
	const functionName = "device_auto_remediation_test.TestDeviceTouchEventOnlyUpdatesSequenceData"
	var (
		generator                     = mockDataGenerator.NewGenerator(1, 1, 0, false)
		devices                       = generator.Devices
		device                        = devices[0]
		entityName                    = "uem.device"
		deviceEntityKey               = fmt.Sprintf("%s%s%s", device.TenantUuid, device.Uuid, device.ChannelUuid)
		deviceEntityKeyValueFlattened = fmt.Sprintf(
			"tenant_uuid:%s|device_uuid:%s|channel_uuid:%s",
			device.TenantUuid,
			device.Uuid,
			device.ChannelUuid,
		)
	)

	// Create bare bones device record with an application
	messages := generator.GenerateDeviceCreateMessagesWithSetup(
		devices, func(event *uemPublicSchema.UemDeviceCreate) {
			event.SequenceNumber = 1
		},
	)

	correlationIds := lo.Map(
		messages,
		func(item *streaming.EventReturn, index int) string {
			return item.CorrelationId()
		},
	)

	logContext := log.NewLogContextWithCorrelationIds(correlationIds...)
	ingestionStartup.Producer().Produce(messages)

	var (
		sequenceUpdatedAt string
		deviceUpdatedAt   string
	)

	deviceSearchQueries := createSearchQueries(
		logContext,
		constants.UemDeviceIndex,
		device.TenantUuid,
		map[string]any{pkg.DeviceUuidProperty: device.Uuid},
	)

	MaxTryAndAssert(
		t,
		logContext,
		ingestionStartup.ReadProvider(),
		deviceSearchQueries,
		functionName,
		func(msearchHits []*repository.Hit[DeviceSource]) (bool, uint) {
			const expectedCount = 1
			updatedDevice := lo.Filter(
				msearchHits,
				func(item *repository.Hit[DeviceSource], _ int) bool {
					// ensure both timestamps are populated
					return item.Source.CreatedAt != nil && item.Source.UpdatedAt != nil
				},
			)

			if Len(logContext, msearchHits, expectedCount, shouldHaveOneDocumentErrorMessage) &&
				Len(logContext, updatedDevice, expectedCount, shouldHaveOneDocumentErrorMessage) {
				return true, expectedCount
			}

			return false, expectedCount
		},
		func(hits []*repository.Hit[DeviceSource]) {
			require.Len(t, hits, 1, shouldHaveOneDocumentErrorMessage)
			deviceUpdatedAt = *hits[0].Source.UpdatedAt
		},
		context.Background(),
	)

	sequenceSearchQueries := createSearchQueries(
		logContext,
		constants.UemSequenceNumberIndex,
		device.TenantUuid,
		map[string]any{
			constants.EntityName: entityName,
		},
		map[string]any{
			constants.EntityKey: deviceEntityKey,
		},
	)

	MaxTryAndAssert(
		t,
		logContext,
		ingestionStartup.ReadProvider(),
		sequenceSearchQueries,
		functionName,
		func(msearchHits []*repository.Hit[SequenceNumberSource]) (bool, uint) {
			const expectedCount = 1

			found := lo.Filter(
				msearchHits,
				func(item *repository.Hit[SequenceNumberSource], _ int) bool {
					return *item.Source.EntityName == entityName && *item.Source.EntityKey == deviceEntityKey
				},
			)

			if Len(logContext, found, expectedCount, shouldHaveOneDocumentErrorMessage) {
				return true, expectedCount
			}

			return false, expectedCount
		},
		func(hits []*repository.Hit[SequenceNumberSource]) {
			require.Len(t, hits, 1, shouldHaveOneDocumentErrorMessage)

			hit := hits[0]

			assert.NotNil(t, hit)
			assert.Equal(t, device.TenantUuid, *hit.Source.TenantUUID)
			assert.Equal(t, entityName, *hit.Source.EntityName)
			assert.Equal(t, deviceEntityKey, *hit.Source.EntityKey)
			assert.Equal(t, deviceEntityKeyValueFlattened, *hit.Source.EntityKeyValuesFlattened)
			assert.Equal(t, int64(1), *hit.Source.SequenceNumber)
			assert.NotNil(t, hit.Source.UpdatedAt)
			sequenceUpdatedAt = *hit.Source.UpdatedAt
		},
		context.Background(),
	)

	// send touch event
	messages = []*streaming.EventReturn{
		generator.GenerateDeviceTouchMessage(device, func(event *uemPublicSchema.UemDeviceTouch) {
			event.SequenceNumber = 1 // no changes to device, hence the sequence number should be 1
		}),
	}

	correlationIds = lo.Map(
		messages,
		func(item *streaming.EventReturn, index int) string {
			return item.CorrelationId()
		},
	)

	logContext = log.NewLogContextWithCorrelationIds(correlationIds...)

	ingestionStartup.Producer().Produce(messages)

	// sequence index should be updated
	MaxTryAndAssert(
		t,
		logContext,
		ingestionStartup.ReadProvider(),
		sequenceSearchQueries,
		functionName,
		func(msearchHits []*repository.Hit[SequenceNumberSource]) (bool, uint) {
			const expectedCount = 1

			found := lo.Filter(
				msearchHits,
				func(item *repository.Hit[SequenceNumberSource], _ int) bool {
					return *item.Source.EntityName == entityName && *item.Source.EntityKey == deviceEntityKey &&
						// sequence no should be updated
						item.Source.UpdatedAt != nil && *item.Source.UpdatedAt != sequenceUpdatedAt
				},
			)

			if Len(logContext, found, expectedCount, shouldHaveOneDocumentErrorMessage) {
				return true, expectedCount
			}

			return false, expectedCount
		},
		func(hits []*repository.Hit[SequenceNumberSource]) {
			require.Len(t, hits, 1, shouldHaveOneDocumentErrorMessage)
		},
		context.Background(),
	)

	// sequence index was updated but device index should not be updated
	MaxTryAndAssert(
		t,
		logContext,
		ingestionStartup.ReadProvider(),
		deviceSearchQueries,
		functionName,
		func(msearchHits []*repository.Hit[DeviceSource]) (bool, uint) {
			const expectedCount = 1
			updatedDevice := lo.Filter(
				msearchHits,
				func(item *repository.Hit[DeviceSource], _ int) bool {
					// device should not be updated
					return item.Source.CreatedAt != nil && item.Source.UpdatedAt != nil &&
						*item.Source.UpdatedAt == deviceUpdatedAt
				},
			)

			if Len(logContext, msearchHits, expectedCount, shouldHaveOneDocumentErrorMessage) &&
				Len(logContext, updatedDevice, expectedCount, shouldHaveOneDocumentErrorMessage) {
				return true, expectedCount
			}

			return false, expectedCount
		},
		func(hits []*repository.Hit[DeviceSource]) {
			require.Len(t, hits, 1, shouldHaveOneDocumentErrorMessage)
		},
		context.Background(),
	)
}

