func TestRemediationOfStaleDeviceDocuments(t *testing.T) {
	const functionName = "device_auto_remediation_test.TestRemediationOfStaleDeviceDocuments"
	var (
		generator = mockDataGenerator.NewGenerator(1, 3, 0, false)
		devices   = generator.Devices
		device    = devices[0]
	)

	// Create bare bones device record with an application
	messages := generator.GenerateDeviceCreateMessagesWithSetup(
		devices, func(event *uemPublicSchema.UemDeviceCreate) {
			event.SequenceNumber = 1
		},
	)

	correlationIds := lo.Map(
		messages,
		func(item *streaming.EventReturn, index int) string {
			return item.CorrelationId()
		},
	)

	logContext := log.NewLogContextWithCorrelationIds(correlationIds...)
	ingestionStartup.Producer().Produce(messages)

	waitForRecord(
		t,
		logContext,
		[]string{constants.UemDeviceIndex},
		3,
		device.TenantUuid,
	)

	// setup mock server to produce the full state events
	fullStateEventsMap := generateFullStateEventsForStaleDevices(generator, devices)
	// start yats mock server
	yatsServer := startYatsMockServer(t)
	defer yatsServer.Close()

	// start DST mock server
	// produce the full state event
	dstServer := startDstMockServer(t, nil, nil, fullStateEventsMap)
	defer dstServer.Close()

	// wait for 10s and then remediate devices older than 5s
	time.Sleep(10 * time.Second)

	// Check for stale documents and remediate manually for testing
	// all the documents inserted so far for would be picked up (devices from other test as well)
	remediationStartup.StaleEntityDetector().DetectAndRemediate(
		logContext,
		time.Second,
		&generator.Tenants[0].TenantUuid,
	)

	searchQueries := createSearchQueries(
		logContext,
		constants.UemDeviceIndex,
		device.TenantUuid,
	)

	MaxTryAndAssert(
		t,
		logContext,
		ingestionStartup.ReadProvider(),
		searchQueries,
		functionName,
		func(msearchHits []*repository.Hit[DeviceSource]) (bool, uint) {
			const expectedCount = 3
			updatedDevice := lo.Filter(
				msearchHits,
				func(item *repository.Hit[DeviceSource], _ int) bool {
					return item.Source.ComplianceStatus != nil
				},
			)

			if Len(logContext, msearchHits, expectedCount, shouldHaveOneDocumentErrorMessage) &&
				Len(logContext, updatedDevice, expectedCount, shouldHaveOneDocumentErrorMessage) {
				return true, expectedCount
			}

			return false, expectedCount
		},
		func(hits []*repository.Hit[DeviceSource]) {
			require.Len(t, hits, 3, shouldHaveOneDocumentErrorMessage)
			for _, hit := range hits {
				assert.Equal(t, "COMPLIANT", *hit.Source.ComplianceStatus)
			}
		},
		context.Background(),
	)
}

