```go
// index_missing_properties_detector.go

type MissingPropertiesParams struct {
    RequiredProperties []string
    DefaultValues     map[string]any
}

// NewMissingPropertiesParams creates a new MissingPropertiesParams instance,
// returns nil if required properties are empty
func NewMissingPropertiesParams(
    requiredProperties []string,
    defaultValues map[string]any,
) *MissingPropertiesParams {
    if len(requiredProperties) == 0 {
