	"airwatch/uem/gumdrop-ingestion/pkg/repository/constants"
	"airwatch/uem/gumdrop-ingestion/pkg/scheduler"
)

type StaleEntityParams struct {
	StalenessThreshold string
	RequiredProperties []string
	RangeFilters       []map[string]*repository.RangeFieldOperators
}

func NewStaleEntityDetector(
	schemaMapper schemaMapping.SchemaMapper,
	scheduler scheduler.Scheduler,
	client repository.NoSqlRepository,
	remediationRequestEmitter emitter.RemediationRequestEmitter,
	schedulerInterval time.Duration,
	searchBatchSize int,
	remediationRequestInterval time.Duration,
	defaultStalenessThreshold time.Duration,
) DriftDetector[StaleEntityParams] {
	params := StaleEntityParams{
		StalenessThreshold: repository.FormatDuration(defaultStalenessThreshold),
		RequiredProperties: []string{constants.UpdatedAt},
		RangeFilters: []map[string]*repository.RangeFieldOperators{
			{
				constants.UpdatedAt: {
					LessThan: fmt.Sprintf("now-%s", repository.FormatDuration(defaultStalenessThreshold)),
				},
			},
		},
	}

	return newBaseDriftDetector[StaleEntityParams](
		params,
		client,
		remediationRequestEmitter,
		scheduler,
		schemaMapper,
		schedulerInterval,
		searchBatchSize,
		remediationRequestInterval,
	)
}

func (p StaleEntityParams) ShouldProcess(remediationConfig *schemaMapping.RemediationConfig) bool {
	return true
}

func (p StaleEntityParams) CreateQuery(
	logContext *log.Context,
	tenantUuid *string,
	indexKey string,
	indexMetadata *schemaMapping.IndexMetadata,
	remediationConfig *schemaMapping.RemediationConfig,
	searchBatchSize int,
) *repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]] {
	termFilters := []map[string]any{}
	if tenantUuid != nil {
		termFilters = []map[string]any{{tenantUuidPropertyName: tenantUuid}}
	}

	queryBody := repository.NewRangeQueryRequest[repository.Params](
		logContext,
		termFilters,
		p.RangeFilters,
		searchBatchSize,
		indexMetadata.KeyProperties,
		p.RequiredProperties,
	)

	queryBody.WithSort(map[string]string{"_id": "asc"})

	return &repository.QueryDetailsItem[*repository.QueryRequest[repository.Params]]{
		Indices:    []string{indexKey},
		Body:       queryBody,
		LogContext: queryBody.LogContext,
	}
}
